// // This module decrements its count value on each positive edge of the clock signal. If a reset signal is received (rst=1), the count value resets to zero. The counter rolls over to zero when it reaches the minimum value of one (0001 in binary).
module top_module(clk, rst, count);input clk, rst;
  output reg [3:0] count;

  always @(posedge clk, posedge rst) begin
    if (rst) begin
      count <= 4'b0;
    end else if (count == 4'b1001) begin
      count <= 4'b0;
    end else begin
      count <= count + 1;
    end
  end

endmodule
